    background: var(--border);
}

.stores-table .img-cell {
    width: 60px;
}

.store-thumb {
    width: 50px;
    height: 40px;
    object-fit: cover;
    border-radius: 4px;
}

.name-cell a {
    color: var(--primary);
    text-decoration: none;
    font-weight: 500;
}

.name-cell a:hover {
    text-decoration: underline;
}

.country-cell {
    font-size: 1.2rem;
    width: 80px;
}

.country-display {
    display: inline-flex;
    align-items: center;
    gap: 0.35rem;
}

.country-code {
    font-size: 0.95rem;
    font-weight: 600;
}

.flag-emoji {
    line-height: 1;
}

.temp-cell,
.humidity-cell {
    width: 100px;
}

.temp-badge,
.humidity-badge {
    display: inline-block;
    padding: 0.4rem 0.8rem;
    border-radius: 4px;
    font-weight: 600;
    font-size: 0.9rem;
    color: white;
}

.temp-cold {
    background: #2196F3;
}

.temp-normal {
    background: #4CAF50;
}

