    background: #FFC107;
    color: #333;
}

.humidity-normal {
    background: #4CAF50;
}

.humidity-high {
    background: #00BCD4;
}

.shelves-cell {
    text-align: center;
    font-weight: 600;
}

.actions-cell {
    width: 150px;
    text-align: center;
    vertical-align: middle;
    white-space: nowrap;
}

.actions-cell .btn-sm {
    margin: 0 0.2rem;
}

.btn-secondary {
    background: #757575;
    color: white;
}

.btn-sm {
    padding: 0.4rem 0.8rem;
    font-size: 0.85rem;
    border: none;
    border-radius: 4px;
    cursor: pointer;
    display: inline-flex;
    align-items: center;
    gap: 0.3rem;
    transition: all 0.2s ease;
}

.btn-info {
    background: var(--accent);
    color: white;
}

.btn-warning {
    background: #ff9800;
    color: white;
}

