    background: #f44336;
    color: white;
}

.btn-sm:hover {
    opacity: 0.8;
    transform: scale(1.05);
}

@media (max-width: 768px) {
    .stores-table-container {
        font-size: 0.85rem;
    }

    .stores-table th,
    .stores-table td {
        padding: 0.5rem;
    }

    .store-thumb {
        width: 40px;
        height: 30px;
    }

    .header-actions {
        flex-direction: column;
    }

    .header-actions .btn {
        width: 100%;
        justify-content: center;
    }
}
</style>
{% endblock %}

