{% extends "base.html" %}

{% block title %}Almacenes - FIWARE{% endblock %}

{% block content %}
<div class="container">
    <div class="page-header">
        <h1 data-i18n="stores.title">Almacenes</h1>
        <div class="header-actions">
            <a href="/stores/new" class="btn btn-primary" data-i18n="stores.add">+ Añadir Almacén</a>
            <a href="/stores/map" class="btn btn-secondary">
                <i class="fas fa-map"></i> <span data-i18n="stores.view_map">Ver Mapa</span>
            </a>
        </div>
    </div>

    {% if error %}
    <div class="alert alert-error">{{ error }}</div>
    {% endif %}

    <div class="stores-table-container">
        <table class="stores-table">
            <thead>
                <tr>
                    <th scope="col" data-i18n="table.image">Imagen</th>
                    <th scope="col" data-i18n="table.name">Nombre</th>
                    <th scope="col" data-i18n="table.country">País</th>
                    <th scope="col" data-i18n="table.temperature">Temperatura</th>
                    <th scope="col" data-i18n="table.humidity">Humedad</th>
                    <th scope="col" data-i18n="table.shelves_count">Estanterías</th>
                    <th scope="col" data-i18n="stores.actions">Acciones</th>
                </tr>
            </thead>
            <tbody>
                {% for store in stores %}
                <tr>
                    <td class="img-cell">
                        <img src="{{ store.image.value if store and store.image else 'https://via.placeholder.com/50x40' }}" alt="{{ store.name.value if store and store.name else '-' }}" class="store-thumb">
                    </td>
                    <td class="name-cell">
                        <a href="/stores/{{ store.id.split(':')[-1] }}">{{ store.name.value if store and store.name else '-' }}</a>
                    </td>
                    {% set country_code = (store.address.value.addressCountry | upper) if store and store.address and store.address.value and store.address.value.addressCountry else '' %}
                    <td class="country-cell">
                        {% if country_code %}
                        <span class="country-display">
                            <img
                                src="https://flagcdn.com/24x18/{{ country_code | lower }}.png"
                                alt=""
                                class="country-flag"
                                loading="lazy"
                                width="24"
                                height="18">
                            <span class="country-code">{{ country_code }}</span>
                        </span>
                        {% else %}
                        <span class="na">—</span>
                        {% endif %}
                    </td>
                    <td class="temp-cell">
                        {% if store.temperature and store.temperature.value is not none %}
                            {% set temp_value = store.temperature.value | float %}
                            <span class="temp-badge {% if temp_value < 15 %}temp-cold{% elif temp_value <= 25 %}temp-normal{% else %}temp-hot{% endif %}">
                                {{ store.temperature.value }}°C
                            </span>
                        {% else %}
                            <span class="na">—</span>
                        {% endif %}
                    </td>
                    <td class="humidity-cell">
                        {% if store.relativeHumidity and store.relativeHumidity.value is not none %}
                            {% set humidity_value = store.relativeHumidity.value | float %}
                            <span class="humidity-badge {% if humidity_value < 30 %}humidity-low{% elif humidity_value <= 70 %}humidity-normal{% else %}humidity-high{% endif %}">
                                {{ store.relativeHumidity.value }}%
                            </span>
                        {% else %}
                            <span class="na">—</span>
                        {% endif %}
                    </td>
                    <td class="shelves-cell">{{ store.shelf_count }}</td>
                    <td class="actions-cell">
                        <a href="/stores/{{ store.id.split(':')[-1] }}" class="btn btn-sm btn-info" data-i18n-title="actions.view_details" title="Ver detalles">
                            <i class="fas fa-eye"></i>
                        </a>
                        <a href="/stores/{{ store.id.split(':')[-1] }}/edit" class="btn btn-sm btn-warning" data-i18n-title="actions.edit" title="Editar">
                            <i class="fas fa-edit"></i>
                        </a>
                        <button class="btn btn-sm btn-danger btn-delete" data-id="{{ store.id }}" data-i18n-title="actions.delete" title="Borrar">
                            <i class="fas fa-trash"></i>
                        </button>
                    </td>
                </tr>
                {% endfor %}
            </tbody>
        </table>
    </div>
</div>
{% endblock %}

{% block extra_css %}
<style>
.header-actions {
    display: flex;
    gap: 1rem;
    flex-wrap: wrap;
}

.stores-table-container {
    overflow-x: auto;
    margin-top: 2rem;
    border-radius: 8px;
    box-shadow: 0 2px 8px rgba(0,0,0,0.1);
}

