    background: #FFC107;
    color: #333;
}

.humidity-normal {
    background: #4CAF50;
}

.humidity-high {
    background: #00BCD4;
}

.shelves-cell {
    text-align: center;
    font-weight: 600;
}

.actions-cell {
    width: 150px;
